-- Ken's Hardened V2 Fix

local b64_0xl1I1ll = {}
local char_0xIIIIIl='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0x11l1lI=1,#char_0xIIIIIl do b64_0xl1I1ll[char_0xIIIIIl:sub(i_0x11l1lI,i_0x11l1lI)] = i_0x11l1lI - 1 end

function b64_0xl1I1ll.dec_0xIlII1l(d_0xIl1I11)
    d_0xIl1I11 = string.gsub(d_0xIl1I11, '[^'..char_0xIIIIIl..'=]', '')
    local r_0xl1IlIl = {}
    for i_0x11l1lI=1, #d_0xIl1I11, 4 do
        local c_0xIIIIlI = b64_0xl1I1ll[d_0xIl1I11:sub(i_0x11l1lI,i_0x11l1lI)] or 0
        local c_0xll1lIl = b64_0xl1I1ll[d_0xIl1I11:sub(i_0x11l1lI+1,i_0x11l1lI+1)] or 0
        local c_0xlIl1Il, c_0xIIIlll = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIl1I11:sub(i_0x11l1lI+2,i_0x11l1lI+2)
        if ch3 == "=" then has3 = false else c_0xlIl1Il = b64_0xl1I1ll[ch3] or 0 end
        local ch4 = d_0xIl1I11:sub(i_0x11l1lI+3,i_0x11l1lI+3)
        if ch4 == "=" then has4 = false else c_0xIIIlll = b64_0xl1I1ll[ch4] or 0 end
        local b_0xI111II = c_0xIIIIlI * (2^18) + c_0xll1lIl * (2^12) + c_0xlIl1Il * (2^6) + c_0xIIIlll
        local b_0xIl1lI1 = math.floor(b_0xI111II / (2^16)) % (2^8)
        local b_0xI1IlIl = math.floor(b_0xI111II / (2^8)) % (2^8)
        local b_0xI1IIIl = b_0xI111II % (2^8)
        table.insert(r_0xl1IlIl, string.char(b_0xIl1lI1))
        if has3 then table.insert(r_0xl1IlIl, string.char(b_0xI1IlIl)) end
        if has4 then table.insert(r_0xl1IlIl, string.char(b_0xI1IIIl)) end
    end
    return table.concat(r_0xl1IlIl)
end


local function bxor_0x1l1lll(a_0xIII1ll,b_0xIllII1)
    if bit32 then return bit32.bxor(a_0xIII1ll,b_0xIllII1) end
    local r_0xIlI1ll = 0
    for i_0xIlllll = 0, 7 do
        local x_0x1IIll1 = a_0xIII1ll % 2
        local y_0xI1lIll = b_0xIllII1 % 2
        if x_0x1IIll1 ~= y_0xI1lIll then r_0xIlI1ll = r_0xIlI1ll + (2^i_0xIlllll) end
        a_0xIII1ll = math.floor(a_0xIII1ll / 2)
        b_0xIllII1 = math.floor(b_0xIllII1 / 2)
    end
    return r_0xIlI1ll
end


local function bxor_str_0xlIIlIl(s_0xIIII1I, k_0xlIlIIl)
    local r_0xll1IlI = {}
    for i_0xllIIl1=1, #s_0xIIII1I do
        local b_0xll1I1l = string.byte(s_0xIIII1I, i_0xllIIl1)
        local kb_0xllllll = string.byte(k_0xlIlIIl, (i_0xllIIl1-1) % #k_0xlIlIIl + 1)
        r_0xll1IlI[i_0xllIIl1] = string.char(bxor_0x1l1lll(b_0xll1I1l, kb_0xllllll))
    end
    return table.concat(r_0xll1IlI)
end


local function getkeys_0x11llll()
    local seed = b64_0xl1I1ll.dec_0xIlII1l("ZElZWW5WdE0=")
    local k1_enc = b64_0xl1I1ll.dec_0xIlII1l("KT8DNyYdPnU=")
    local k2_enc = b64_0xl1I1ll.dec_0xIlII1l("KAwdbwgYEis=")
    return bxor_str_0xlIIlIl(k1_enc, seed), bxor_str_0xlIIlIl(k2_enc, seed)
end


local function cff_0xIIIlII(a_0xIIl1II)
    local st_0xIllI1l = 0
    local res_0xlIlI11 = a_0xIIl1II
    while true do
        if st_0xIllI1l == 0 then
            res_0xlIlI11 = res_0xlIlI11 + 1
            st_0xIllI1l = 1
        elseif st_0xIllI1l == 1 then
            res_0xlIlI11 = res_0xlIlI11 * 2
            st_0xIllI1l = 2
        elseif st_0xIllI1l == 2 then
            res_0xlIlI11 = res_0xlIlI11 - 3
            st_0xIllI1l = 3
        else
            break
        end
    end
    return res_0xlIlI11
end


local function chain_0xlIl1ll(x) return x*2 end
local function chain_0x1I1II1(x) return chain_0xlIl1ll(x)+1 end


local d_0x1lIl1I = {
  {op=255, val="", is_enc=true},
}
local pc_0xlIlllI = 1
local stk_0xIlllI1 = {}
stk_0xIlllI1._jmp = nil


local disp_0xlIlI1l = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0x11llll()

local state_0xlllIlI = 0
while true do
    if state_0xlllIlI == 0 then  -- FETCH
        if pc_0xlIlllI > #d_0x1lIl1I then break end
        local inst = d_0x1lIl1I[pc_0xlIlllI]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xl1I1ll.dec_0xIlII1l(val)
            d = bxor_str_0xlIIlIl(d, k2)
            val = bxor_str_0xlIIlIl(d, k1)
        end
        stk_0xIlllI1._jmp = nil
        pc_0xlIlllI = pc_0xlIlllI + 1
        cur_op_0xlllllI = opcode
        cur_val_0xIlIllI = val
        state_0xlllIlI = 1

    elseif state_0xlllIlI == 1 then  -- EXECUTE
        local handler = disp_0xlIlI1l[cur_op_0xlllllI]
        if handler then
            handler(stk_0xIlllI1, cur_val_0xIlIllI)
        end
        if stk_0xIlllI1._jmp then
            pc_0xlIlllI = pc_0xlIlllI + stk_0xIlllI1._jmp
        end
        state_0xlllIlI = 0
    else
